  /// Pushes the global environment onto the stack.
  void lua_pushglobaltable(Pointer<Void> L);

  /// lua_pushinteger
  ///
  /// Stack: [-0, +1, &ndash;]
  ///
  /// Pushes an integer with value n onto the stack.
  void lua_pushinteger(Pointer<Void> L, Int64 n);

  /// lua_pushlightuserdata
  ///
  /// Stack: [-0, +1, &ndash;]
  ///
  /// Pushes a light userdata onto the stack.
  void lua_pushlightuserdata(Pointer<Void> L, Pointer<Void> p);

  /// lua_pushliteral
  ///
  /// Stack: [-0, +1, &ndash;]
  ///
  /// This macro is equivalent to lua_pushstring, but should be used only when s is a literal string. (Lua may optimize this case.)
  IntPtr lua_pushliteral(Pointer<Void> L, Pointer<Void> s);

  /// lua_pushlstring
  ///
  /// Stack: [-0, +1, &ndash;]
  ///
  /// Pushes the string pointed to by s with size len onto the stack. Lua will make or reuse an internal copy of the given string, so the memory at s can be freed or reused immediately after the function returns. The string can contain any binary data, including embedded zeros.
  /// Besides memory allocation errors, this function may raise an error if the string is too large.
  IntPtr lua_pushlstring(Pointer<Void> L, Pointer<Void> s, IntPtr len);

  /// lua_pushnil
  ///
  /// Stack: [-0, +1, &ndash;]
  ///
  /// Pushes a nil value onto the stack.
  void lua_pushnil(Pointer<Void> L);

  /// lua_pushnumber
  ///
  /// Stack: [-0, +1, &ndash;]
  ///
  /// Pushes a float with value n onto the stack.
  void lua_pushnumber(Pointer<Void> L, Double n);

  /// lua_pushstring
  ///
  /// Stack: [-0, +1, &ndash;]
  ///
  /// Pushes the zero-terminated string pointed to by s onto the stack. Lua will make or reuse an internal copy of the given string, so the memory at s can be freed or reused immediately after the function returns.
  /// If s is NULL, pushes nil and returns NULL.
  IntPtr lua_pushstring(Pointer<Void> L, Pointer<Void> s);

  /// lua_pushthread
  ///
  /// Stack: [-0, +1, &ndash;]
  ///
  /// Pushes the thread represented by L onto the stack. Returns 1 if this thread is the main thread of its state.
  Int32 lua_pushthread(Pointer<Void> L);

  /// lua_pushvalue
  ///
  /// Stack: [-0, +1, &ndash;]
  ///
  /// Pushes a copy of the element at the given index onto the stack.
  void lua_pushvalue(Pointer<Void> L, Int32 index);

  /// lua_pushvfstring
  ///
  /// Stack: [-0, +1, &ndash;]
  ///
  /// Equivalent to lua_pushfstring, except that it receives a va_list instead of a variable number of arguments, and it does not raise errors. Instead, in case of errors it pushes the error message and returns NULL.
  IntPtr lua_pushvfstring(Pointer<Void> L, Pointer<Void> fmt, Pointer<VarArgs> argp);

  /// lua_rawequal
  ///
  /// Stack: [-0, +0, &ndash;]
  ///
  /// Returns 1 if the two values in indices index1 and index2 are primitively equal (that is, equal without calling the __eq metamethod). Otherwise returns 0. Also returns 0 if any of the indices are not valid.
  Int32 lua_rawequal(Pointer<Void> L, Int32 index1, Int32 index2);

  /// lua_rawget
  ///
  /// Stack: [-1, +1, &ndash;]
  ///
  /// Similar to lua_gettable, but does a raw access (i.e., without metamethods). The value at index must be a table.
  Int32 lua_rawget(Pointer<Void> L, Int32 index);

  /// lua_rawgeti
  ///
  /// Stack: [-0, +1, &ndash;]
  ///
  /// Pushes onto the stack the value t[n], where t is the table at the given index. The access is raw, that is, it does not use the __index metavalue.
  Int32 lua_rawgeti(Pointer<Void> L, Int32 index, Int64 n);

  /// lua_rawgetp
  ///
  /// Stack: [-0, +1, &ndash;]
  ///
  /// Pushes onto the stack the value t[k], where t is the table at the given index and k is the pointer p represented as a light userdata. The access is raw; that is, it does not use the __index metavalue.
  Int32 lua_rawgetp(Pointer<Void> L, Int32 index, Pointer<Void> p);

  /// lua_rawlen
  ///
  /// Stack: [-0, +0, &ndash;]
  ///
  /// Returns the raw "length" of the value at the given index: for strings, this is the string length; for tables, this is the result of the length operator ('#') with no metamethods; for userdata, this is the size of the block of memory allocated for the userdata. For other values, this call returns 0.
  Uint64 lua_rawlen(Pointer<Void> L, Int32 index);

  /// lua_rawset
  ///
  /// Stack: [-1, +0, &ndash;]
  ///
  /// Similar to lua_settable, but does a raw assignment (i.e., without metamethods). The value at index must be a table.
  void lua_rawset(Pointer<Void> L, Int32 index);

  /// lua_rawseti
  ///
  /// Stack: [-1, +0, &ndash;]
  ///
  /// Does the equivalent of t[i] = v, where t is the table at the given index and v is the value on the top of the stack.
  void lua_rawseti(Pointer<Void> L, Int32 index, Int64 i);

  /// lua_rawsetp
  ///
  /// Stack: [-1, +0, &ndash;]
  ///
  /// Does the equivalent of t[p] = v, where t is the table at the given index, p is encoded as a light userdata, and v is the value on the top of the stack.
  void lua_rawsetp(Pointer<Void> L, Int32 index, Pointer<Void> p);

  /// lua_register
  ///
  /// Stack: [-1, +0, &ndash;]
  ///
  /// Sets the C function f as the new value of global name. It is defined as a macro: #define lua_register(L,n,f) \ (lua_pushcfunction(L, f), lua_setglobal(L, n))
  void lua_register(Pointer<Void> L, Pointer<Void> name, Pointer<NativeFunction<lua_CFunction_Func>> f);

  /// lua_remove
  ///
  /// Stack: [-1, +0, &ndash;]
  ///
  /// Removes the element at the given valid index, shifting down the elements above this index to fill the gap. This function cannot be called with a pseudo-index, because a pseudo-index is not an actual stack position.
  void lua_remove(Pointer<Void> L, Int32 index);

  /// lua_replace
  ///
  /// Stack: [-1, +0, &ndash;]
  ///
  /// Moves the top element into the given valid index without shifting any element (therefore replacing the value at that given index), and then pops the top element.
  void lua_replace(Pointer<Void> L, Int32 index);

  /// lua_resume
  ///
  /// Stack: [-?, +?, &ndash;]
  ///
  /// Starts and resumes a coroutine in the given thread L.
  /// To resume a suspended coroutine, you remove the *nresults yielded values from its stack, push the values to be passed as results from yield, and then call lua_resume.
  Int32 lua_resume(Pointer<Void> L, Pointer<Void> from, Int32 nargs, Pointer<Void> nresults);

  /// lua_rotate
  ///
  /// Stack: [-0, +0, &ndash;]
  ///
  /// Rotates the stack elements between the valid index idx and the top of the stack. The elements are rotated n positions in the direction of the top, for a positive n, or -n positions in the direction of the bottom, for a negative n. The absolute value of n must not be greater than the size of the slice being rotated. This function cannot be called with a pseudo-index, because a pseudo-index is not an actual stack position.
  void lua_rotate(Pointer<Void> L, Int32 idx, Int32 n);

  /// lua_setallocf
  ///
  /// Stack: [-0, +0, &ndash;]
  ///
  /// Changes the allocator function of a given state to f with user data ud.
  void lua_setallocf(Pointer<Void> L, Pointer<NativeFunction<lua_Alloc_Func>> f, Pointer<Void> ud);

  /// lua_setfield
  ///
  /// Stack: [-1, +0, &ndash;]
  ///
  /// Does the equivalent to t[k] = v, where t is the value at the given index and v is the value on the top of the stack.
  void lua_setfield(Pointer<Void> L, Int32 index, Pointer<Void> k);

  /// lua_setglobal
  ///
  /// Stack: [-1, +0, &ndash;]
  ///
  /// Pops a value from the stack and sets it as the new value of global name.
  void lua_setglobal(Pointer<Void> L, Pointer<Void> name);

  /// lua_sethook
  ///
  /// Stack: [-0, +0, &ndash;]
  ///
  /// Sets the debugging hook function.
  /// Hooks are disabled by setting mask to zero.
  void lua_sethook(Pointer<Void> L, Pointer<NativeFunction<lua_Hook_Func>> f, Int32 mask, Int32 count);

  /// lua_seti
  ///
  /// Stack: [-1, +0, &ndash;]
  ///
  /// Does the equivalent to t[n] = v, where t is the value at the given index and v is the value on the top of the stack.
  void lua_seti(Pointer<Void> L, Int32 index, Int64 n);

  /// lua_setiuservalue
  ///
  /// Stack: [-1, +0, &ndash;]
  ///
  /// Pops a value from the stack and sets it as the new n-th user value associated to the full userdata at the given index. Returns 0 if the userdata does not have that value.
  Int32 lua_setiuservalue(Pointer<Void> L, Int32 index, Int32 n);

  /// lua_setlocal
  ///
  /// Stack: [-(0|1), +0, &ndash;]
  ///
  /// Sets the value of a local variable of a given activation record. It assigns the value on the top of the stack to the variable and returns its name. It also pops the value from the stack.
  /// Parameters ar and n are as in the function lua_getlocal.
  IntPtr lua_setlocal(Pointer<Void> L, Pointer<Void> ar, Int32 n);

  /// lua_setmetatable
  ///
  /// Stack: [-1, +0, &ndash;]
  ///
  /// Pops a table or nil from the stack and sets that value as the new metatable for the value at the given index. (nil means no metatable.)
  Int32 lua_setmetatable(Pointer<Void> L, Int32 index);

  /// lua_settable
  ///
  /// Stack: [-0, +0, &ndash;]
  ///
  /// Does the equivalent to t[k] = v, where t is the value at the given index, v is the value on the top of the stack, and k is the value just below the top.
  void lua_settable(Pointer<Void> L, Int32 index);

  /// lua_settop
  ///
  /// Stack: [-0, +0, &ndash;]
  ///
  /// Receives any acceptable stack index, or 0, and sets the stack top to this index. If the new top is greater than the old one, then the new elements are filled with nil. If index is 0, then all stack elements are removed.
  void lua_settop(Pointer<Void> L, Int32 index);

  /// lua_setupvalue
  ///
  /// Stack: [-(0|1), +0, &ndash;]
  ///
  /// Sets the value of a closure's upvalue. It assigns the value on the top of the stack to the upvalue and returns its name. It also pops the value from the stack.
  /// Parameters funcindex and n are as in the function lua_getupvalue.
  IntPtr lua_setupvalue(Pointer<Void> L, Int32 funcindex, Int32 n);

  /// lua_setwarnf
  ///
  /// Stack: [-0, +0, &ndash;]
  ///
  /// Sets the warning function to be used by Lua to emit warnings (see lua_WarnFunction). The ud parameter sets the value ud passed to the warning function.
  void lua_setwarnf(Pointer<Void> L, Pointer<NativeFunction<lua_WarnFunction_Func>> f, Pointer<Void> ud);

  /// lua_status
  ///
  /// Stack: [-0, +0, &ndash;]
  ///
  /// Returns the status of the thread L.
  /// You can call functions only in threads with status LUA_OK. You can resume threads with status LUA_OK (to start a new coroutine) or LUA_YIELD (to resume a coroutine).
  Int32 lua_status(Pointer<Void> L);

  /// lua_stringtonumber
  ///
  /// Stack: [-0, +1, &ndash;]
  ///
  /// Converts the zero-terminated string s to a number, pushes that number into the stack, and returns the total size of the string, that is, its length plus one. The conversion can result in an integer or a float, according to the lexical conventions of Lua (see &sect;3.1). The string may have leading and trailing whitespaces and a sign. If the string is not a valid numeral, returns 0 and pushes nothing. (Note that the result can be used as a boolean, true if the conversion succeeds.)
  IntPtr lua_stringtonumber(Pointer<Void> L, Pointer<Void> s);

  /// lua_toboolean
  ///
  /// Stack: [-0, +0, &ndash;]
  ///
  /// Converts the Lua value at the given index to a C boolean value (0 or 1). Like all tests in Lua, lua_toboolean returns true for any Lua value different from false and nil; otherwise it returns false. (If you want to accept only actual boolean values, use lua_isboolean to test the value's type.)
  Int32 lua_toboolean(Pointer<Void> L, Int32 index);

  /// lua_tocfunction
  ///
  /// Stack: [-0, +0, &ndash;]
  ///
  /// Converts a value at the given index to a C function. That value must be a C function; otherwise, returns NULL.
  Pointer<NativeFunction<lua_CFunction_Func>> lua_tocfunction(Pointer<Void> L, Int32 index);

  /// lua_toclose
  ///
  /// Stack: [-0, +0, &ndash;]
  ///
  /// Marks the given index in the stack as a to-be-closed slot (see &sect;3.3.8). Like a to-be-closed variable in Lua, the value at that slot in the stack will be closed when it goes out of scope. Here, in the context of a C function, to go out of scope means that the running function returns to Lua, or there is an error, or the slot is removed from the stack through lua_settop or lua_pop, or there is a call to lua_closeslot. A slot marked as to-be-closed should not be removed from the stack by any other function in the API except lua_settop or lua_pop, unless previously deactivated by lua_closeslot.
  /// This function should not be called for an index that is equal to or below an active to-be-closed slot.
  void lua_toclose(Pointer<Void> L, Int32 index);

  /// lua_tointeger
  ///
  /// Stack: [-0, +0, &ndash;]
  ///
  /// Equivalent to lua_tointegerx with isnum equal to NULL.
  Int64 lua_tointeger(Pointer<Void> L, Int32 index);

  /// lua_tointegerx
  ///
  /// Stack: [-0, +0, &ndash;]
  ///
  /// Converts the Lua value at the given index to the signed integral type lua_Integer. The Lua value must be an integer, or a number or string convertible to an integer (see &sect;3.4.3); otherwise, lua_tointegerx returns 0.
  Int64 lua_tointegerx(Pointer<Void> L, Int32 index, Pointer<Void> isnum);

  /// lua_tolstring
  ///
  /// Stack: [-0, +0, &ndash;]
  ///
  /// Converts the Lua value at the given index to a C string. The Lua value must be a string or a number; otherwise, the function returns NULL. If the value is a number, then lua_tolstring also changes the actual value in the stack to a string. (This change confuses lua_next when lua_tolstring is applied to keys during a table traversal.)
  /// The pointer returned by lua_tolstring may be invalidated by the garbage collector if the corresponding Lua value is removed from the stack (see &sect;4.1.3).
  IntPtr lua_tolstring(Pointer<Void> L, Int32 index, Pointer<Void> len);

  /// lua_tonumber
  ///
  /// Stack: [-0, +0, &ndash;]
  ///
  /// Equivalent to lua_tonumberx with isnum equal to NULL.
  Double lua_tonumber(Pointer<Void> L, Int32 index);

  /// lua_tonumberx
  ///
  /// Stack: [-0, +0, &ndash;]
  ///
  /// Converts the Lua value at the given index to the C type lua_Number (see lua_Number). The Lua value must be a number or a string convertible to a number (see &sect;3.4.3); otherwise, lua_tonumberx returns 0.
  Double lua_tonumberx(Pointer<Void> L, Int32 index, Pointer<Void> isnum);

  /// lua_topointer
  ///
  /// Stack: [-0, +0, &ndash;]
  ///
  /// Converts the value at the given index to a generic C pointer (void*). The value can be a userdata, a table, a thread, a string, or a function; otherwise, lua_topointer returns NULL. Different objects will give different pointers. There is no way to convert the pointer back to its original value.
  IntPtr lua_topointer(Pointer<Void> L, Int32 index);

  /// lua_tostring
  ///
  /// Stack: [-0, +0, &ndash;]
  ///
  /// Equivalent to lua_tolstring with len equal to NULL.
  IntPtr lua_tostring(Pointer<Void> L, Int32 index);

  /// lua_tothread
  ///
  /// Stack: [-0, +0, &ndash;]
  ///
  /// Converts the value at the given index to a Lua thread (represented as lua_State*). This value must be a thread; otherwise, the function returns NULL.
  IntPtr lua_tothread(Pointer<Void> L, Int32 index);

  /// lua_touserdata
  ///
  /// Stack: [-0, +0, &ndash;]
  ///
  /// If the value at the given index is a full userdata, returns its memory-block address. If the value is a light userdata, returns its value (a pointer). Otherwise, returns NULL.
  IntPtr lua_touserdata(Pointer<Void> L, Int32 index);

  /// lua_type
  ///
  /// Stack: [-0, +0, &ndash;]
  ///
  /// Returns the type of the value in the given valid index, or LUA_TNONE for a non-valid but acceptable index. The types returned by lua_type are coded by the following constants defined in lua.h: LUA_TNIL, LUA_TNUMBER, LUA_TBOOLEAN, LUA_TSTRING, LUA_TTABLE, LUA_TFUNCTION, LUA_TUSERDATA, LUA_TTHREAD, and LUA_TLIGHTUSERDATA.
  Int32 lua_type(Pointer<Void> L, Int32 index);

  /// lua_typename
  ///
  /// Stack: [-0, +0, &ndash;]
  ///
  /// Returns the name of the type encoded by the value tp, which must be one the values returned by lua_type.
  IntPtr lua_typename(Pointer<Void> L, Int32 tp);

  /// lua_upvalueid
  ///
  /// Stack: [-0, +0, &ndash;]
  ///
  /// Returns a unique identifier for the upvalue numbered n from the closure at index funcindex.
  /// Parameters funcindex and n are as in the function lua_getupvalue, but n cannot be greater than the number of upvalues.
  IntPtr lua_upvalueid(Pointer<Void> L, Int32 funcindex, Int32 n);

  /// lua_upvalueindex
  ///
  /// Stack: [-0, +0, &ndash;]
  ///
  /// Returns the pseudo-index that represents the i-th upvalue of the running function (see &sect;4.2). i must be in the range [1,256].
  Int32 lua_upvalueindex(Int32 i);

  /// lua_upvaluejoin
  ///
  /// Stack: [-0, +0, &ndash;]
  ///
  /// Make the n1-th upvalue of the Lua closure at index funcindex1 refer to the n2-th upvalue of the Lua closure at index funcindex2. 5 - The Auxiliary Library
  /// All functions and types from the auxiliary library are defined in the header file lauxlib.h and have a prefix luaL_.
  /// Several functions in the auxiliary library use internally some extra stack slots. When a function in the auxiliary library uses less than five slots, it does not check the stack size; it simply assumes that there are enough slots.
  /// Functions called luaL_check* always raise an error if the check is not satisfied. 5.1 - Functions and Types
  void lua_upvaluejoin(Pointer<Void> L, Int32 funcindex1, Int32 n1, Int32 funcindex2, Int32 n2);

  /// lua_version
  ///
  /// Stack: [-0, +0, &ndash;]
  ///
  /// Returns the version number of this core.
  Double lua_version(Pointer<Void> L);

  /// lua_warning
  ///
  /// Stack: [-0, +0, &ndash;]
  ///
  /// Emits a warning with the given message. A message in a call with tocont true should be continued in another call to this function.
  void lua_warning(Pointer<Void> L, Pointer<Void> msg, Int32 tocont);

  /// lua_xmove
  ///
  /// Stack: [-?, +?, &ndash;]
  ///
  /// Exchange values between different threads of the same state.
  void lua_xmove(Pointer<Void> from, Pointer<Void> to, Int32 n);

  /// lua_yield
  ///
  /// This function is equivalent to lua_yieldk, but it has no continuation (see &sect;4.5). Therefore, when the thread resumes, it continues the function that called the function calling lua_yield. To avoid surprises, this function should be called only in a tail call.
  Int32 lua_yield(Pointer<Void> L, Int32 nresults);

  /// lua_yieldk
  ///
  /// Yields a coroutine (thread).
  /// When the coroutine is resumed again, Lua calls the given continuation function k to continue the execution of the C function that yielded (see &sect;4.5). This continuation function receives the same stack from the previous function, with the n results removed and replaced by the arguments passed to lua_resume. Moreover, the continuation function receives the value ctx that was passed to lua_yieldk.
  /// This function can raise an error if it is called from a thread with a pending C call with no continuation function (what is called a C-call boundary), or it is called from a thread that is not running inside a resume (typically the main thread). 4.7 - The Debug Interface
  Int32 lua_yieldk(Pointer<Void> L, Int32 nresults, IntPtr ctx, Pointer<NativeFunction<lua_KFunction_Func>> k);

}
